import React, { useState } from "react";
import createAxiosInstance from "../../config/api";
import {useParams} from "react-router-dom";
export { FileUploadDownload as default };

export function FileUploadDownload(editedItem, setEditedItem) {

  const { Id } = useParams();
  const [uploading, setUploading] = useState(false);
  const [progress, setProgress] = useState(0); // 업로드 진행 상태
  const [downloading, setDownloading] = useState(false);
  const [files, setFiles] = useState({
    resumeFileName1: [],
    resumeFileName2: [],
    resumeFileName3: []
  }); // 모든 파일 상태 관리



  const handleFileChange = (event, type) => {
    // const selectedFiles = Array.from(event.target.files);
    // const existingPath =
    //     type === "resumeFileName1"
    //         ? editedItem.applicantFile.find((file) => file.resumeType === "resumeFileName1")
    //         : type === "resumeFileName2"
    //             ? editedItem.applicantFile.find((file) => file.resumeType === "resumeFileName2")
    //             : type === "resumeFileName3"
    //                 ? editedItem.applicantFile.find((file) => file.resumeType === "resumeFileName3")
    //                 : null;
    //
    // if (existingPath && existingPath.fileName && existingPath.fileName.trim() !== "") {
    //   const confirmUpload = window.confirm(
    //       "이미 파일이 저장되어 있습니다. 업로드를 진행하시겠습니까?"
    //   );
  //
  //   if (!confirmUpload) {
  //     // 사용자가 취소를 누르면 파일 선택을 초기화
  //     event.target.value = null;
  //     return; // 업로드를 진행하지 않음
  //   }
  // }
    const selectedFiles = Array.from(event.target.files);

    // 업로드된 파일을 하나씩 비교하기
    selectedFiles.forEach((newFile) => {
      const existingFile = editedItem.applicantFile.find(
          (file) => file.resumeType === type && file.fileName === newFile.name
      );

      if (existingFile) {
        const confirmUpload = window.confirm(
            `이미 ${newFile.name} 파일이 저장되어 있습니다. 업로드를 진행하시겠습니까?`
        );

        if (!confirmUpload) {
          // 사용자가 취소를 누르면 파일 선택을 초기화
          event.target.value = null;
          return; // 업로드를 진행하지 않음
        }
      }
    });
    setFiles((prevFiles) => ({
      ...prevFiles,
      [type]: selectedFiles, // 선택된 파일을 해당 타입에 저장
    }));
  };

  const handleUpload = async () => {
    if (files.resumeFileName1.length === 0 && files.resumeFileName2.length === 0 && files.resumeFileName3.length === 0) {
      alert("파일을 선택해주세요.");
      return;
    }

    const formData = new FormData();
    // 각 파일과 타입을 함께 전송
    files.resumeFileName1.forEach((file) => {
      formData.append("files", file);
      formData.append("resumeTypes", "resumeFileName1");
    });
    // resume2에 해당하는 파일을 추가
    files.resumeFileName2.forEach((file) => {
      formData.append("files", file);
      formData.append("resumeTypes", "resumeFileName2");
    });
    // resume3에 해당하는 파일을 추가
    files.resumeFileName3.forEach((file) => {
      formData.append("files", file);
      formData.append("resumeTypes", "resumeFileName3");
    });

    setUploading(true);
    setProgress(0); // 초기화

    try {
      const axiosInstance = createAxiosInstance();
      await axiosInstance.post(`/personnel/applicant/${Id}/upload`, formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
        onUploadProgress: (progressEvent) => {
          const percentCompleted = Math.round(
            (progressEvent.loaded * 100) / progressEvent.total
          );
          setProgress(percentCompleted);
        },
      });
      const uploadedFiles = response.data; // 서버에서 반환된 파일 목록
      alert("파일 업로드 성공!");

      // 기존에 저장된 파일을 업데이트
      setEditedItem((prevState) => ({
        ...prevState,
        applicantFile: uploadedFiles,
      }));
      setFiles({ resumeFileName1: [], resumeFileName2: [], resumeFileName3: [] });
      } catch (error) {
      console.error("파일 업로드 실패:", error);
      alert("파일 업로드 중 오류가 발생했습니다.");
    } finally {
      setUploading(false);
      setProgress(0); // 업로드 완료 후 초기화
    }
  };

  const handleDownload = async () => {
    setDownloading(true);
    try {
      const axiosInstance = createAxiosInstance();

      // 파일 다운로드 요청
      const response = await axiosInstance.get(`/personnel/applicant/${Id}/download`, {
        responseType: "blob", // 응답을 Blob 형식으로 처리
      });

      // Blob을 URL로 변환하여 다운로드 처리
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download",  "지원자_이력서.zip"); // 파일명 설정
      document.body.appendChild(link);
      link.click();
      link.remove();

      // 다운로드 완료 후 URL 객체를 해제하여 메모리 관리
      window.URL.revokeObjectURL(url);

    } catch (error) {
      console.error("파일 다운로드 실패:", error);
      alert("파일 다운로드 중 오류가 발생했습니다.");
    } finally {
      setDownloading(false);
    }
  };

  //id값을 가져와서 파일 삭제 쿼리 발송
  const fileDelete = async (fileId) =>{
    try {
      const axiosInstance = createAxiosInstance();
      await axiosInstance.delete(`/personnel/applicant/${fileId}/fileDelete`);
      alert("파일 삭제 성공!");
      setEditedItem((prevItem) => ({
        ...prevItem,
        applicantFile: prevItem.applicantFile.filter((file) => file.id !== fileId),
      }));
    } catch (error) {
      console.error("파일 삭제 실패:", error);
      alert("파일 삭제 중 오류가 발생했습니다.");
    }


  }

  return {
    handleFileChange,
    handleUpload,
    handleDownload,
    uploading,
    progress,
    downloading,
    files,
    fileDelete,
  };
}
